"""
MKT Christ Commentary — Isaiah chapter 41
Run: python3 scripts/zc-christ-isaiah-41.py

Source data used:
- data/interlinear/isaiah.json
- data/translation/draft/mediating/isaiah.json

Key decisions in this range:
- v. 4: 'ani hu (I am he) — direct: Christ's ego eimi (John 8:58; 18:5-6)
- vv. 8-9: Israel as servant/offspring of Abraham — shadow: Christ as true Servant and true seed (Gal 3:16)
- v. 10: fear not, I am with you — shadow: Matt 28:20; John 15:5; Phil 4:13
- v. 14: worm Jacob — shadow: Ps 22:6 (the worm-psalm Christ cites from the cross)
- v. 27: good news to Zion first — shadow: Acts 3:26; Rom 1:16
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    # INTENT: Non-destructive merge — existing entries are never overwritten, safe to re-run
    for ch, verses in new_data.items():
        if ch not in existing: existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]: existing[ch][v] = html

ISAIAH = {
"41": {
"1": "<p>A revelation of God: the coastlands are summoned to renew their strength (<em>yaḥălîpû kōaḥ</em>) and come near for judgment. YHWH issues a legal summons to all the nations — the divine court convenes. This cosmic legal scene is the background for Christ as Judge and Advocate: John 5:22 (the Father has given all judgment to the Son); 1 John 2:1 (we have an advocate with the Father, Jesus Christ the righteous). The same God who opens the court in Isaiah 41 has appointed his Son as both the judge and the defense attorney.</p>",
"2": "<p>A revelation of God: who stirred up (<em>hê'îr</em>) the one from the east, whom victory meets at every step? The rhetorical question frames YHWH's sovereignty over historical conquerors — here anticipating Cyrus (cf. 44:28; 45:1). The one who stirs up Cyrus is the same one who raised up Christ: Acts 2:24 (<em>God raised him up, loosing the pangs of death</em>). The language of divine stirring/raising (Hebrew <em>hê'îr</em> = to arouse, awaken) is the resurrection vocabulary before the resurrection.</p>",
"3": "<p>A revelation of God: the conqueror pursues them, passes on safely, his feet scarcely touching the path. The imagery of irresistible, unstoppable advance describes YHWH's agent moving through history. Christ's advance is equally unstoppable: Matthew 16:18 (the gates of Hades shall not prevail against it); Acts 12:24 (the word of God increased and multiplied even through persecution). The one whom YHWH stirs up cannot be stopped — a principle that applies both to Cyrus and to Christ.</p>",
"4": "<p>A direct Christological reference. Who has performed and done this? <em>'ănî YHWH ri'šôn wĕ'et-'aḥărōnîm 'ănî-hû'</em> — I, YHWH, the first; and with the last; I am he. The declaration <em>'ănî hû'</em> (I am he) is one of the most theologically freighted phrases in Isaiah (cf. 43:10,13; 46:4; 48:12). Jesus uses the same absolute <em>ego eimi</em> (I am he) in John 8:58 (<em>before Abraham was, I am</em>) and John 18:5-6 (when the soldiers say they seek Jesus of Nazareth and he says <em>I am he</em>, they fall to the ground). The first and the last is applied explicitly to Christ in Revelation 1:17 and 22:13. YHWH who identifies himself as the first and last in Isaiah 41:4 is the risen Christ of Revelation.</p>",
"5": "<p>A revelation of God: the coastlands see and fear; the ends of the earth tremble. Universal recognition of divine power — the fear of YHWH at his mighty deeds — is the precursor to the universal recognition of Christ: Philippians 2:10-11 (every knee shall bow and every tongue confess that Jesus Christ is Lord). The fear that YHWH's historical acts inspire is the proleptic enactment of what Christ's return will make universal.</p>",
"6": "<p>A revelation of God: each helps his neighbor and says to his brother, <em>be strong!</em> — the frantic mutual encouragement of idol-makers. The irony: those who make non-gods encourage each other frantically in the face of YHWH's power. The human solidarity in idolatry contrasts with the divine solidarity YHWH offers in v. 10 (I will strengthen you). Only YHWH strengthens without fear; human solidarity in false worship collapses under the weight of what it cannot hold.</p>",
"7": "<p>A revelation of God: the craftsman encourages the goldsmith, the hammerer the one who smooths the anvil — they fasten the idol so it cannot totter. The careful fastening of the idol to prevent it from falling is the mark of its helplessness: it cannot stand on its own. The NT contrast is Christ who holds all things together by the word of his power (Col 1:17; Heb 1:3) — the one who needs no fastening, who is the ground on which everything else stands.</p>",
"8": "<p>A shadow: <em>wĕ'attāh yiśrā'ēl 'ab̠dî ya'ăqōb̠ 'ăšer bĕḥartîkā zera' 'ab̠rāhām 'ōhăb̠î</em> — but you, Israel, my servant, Jacob whom I have chosen, the offspring of Abraham my friend. The servant identity of Israel reaches its singular focus in Christ, who is the true Servant (Isa 42:1 quoted in Matt 12:18: <em>behold my servant whom I have chosen</em>). The true seed of Abraham in whom all nations are blessed (Gal 3:16: <em>to your offspring — meaning one — who is Christ</em>) is the one in whom Israel's servant vocation is finally fulfilled.</p>",
"9": "<p>A shadow: <em>you whom I took from the ends of the earth, and called from its farthest corners, saying to you: you are my servant, I have chosen you and not cast you off.</em> The divine choice that persists despite failure — <em>I have not cast you off</em> (<em>lō' mĕ'astîkā</em>) — is the grace that Christ embodies toward all who fail. Romans 11:1-2 applies this to Israel's ongoing status before God: <em>God has not rejected his people whom he foreknew</em>. The one who is not cast off is ultimately Christ, the chosen Servant, and in him all who are his.</p>",
"10": "<p>A shadow: <em>'al-tîrā' kî 'immĕkā 'ānî 'al-tišta' kî-'ănî 'Ĕlōhèkā 'immaṣtîkā 'ap̄-'ăzartîkā 'ap̄-tĕmaktîkā bîmîn ṣidqî</em> — fear not, for I am with you; be not dismayed, for I am your God; I will strengthen you, I will help you, I will uphold you with my righteous right hand. This is one of the most comprehensive promises in all scripture. Christ is the embodiment of each element: <em>I am with you</em> (Matt 28:20: <em>I am with you always, to the end of the age</em>); <em>I will help you</em> (John 15:5: <em>apart from me you can do nothing</em>); <em>I will uphold you</em> (John 10:28-29: no one can snatch them from my hand or the Father's hand). The righteous right hand that upholds is the same right hand at which Christ is seated (Ps 110:1; Acts 2:33).</p>",
"11": "<p>A shadow: all who are incensed against you shall be put to shame and confounded — they shall be as nothing. The divine pledge to vindicate the servant before enemies is fulfilled eschatologically in Christ: Revelation 6:10-11 (the martyrs under the altar ask how long — and the answer is: the vindication is coming); Romans 8:33-34 (who shall bring any charge against God's elect? It is Christ who intercedes). The enemies of Christ's servants are the enemies of the one who holds their right hand.</p>",
"12": "<p>A revelation of God: you shall seek those who contend with you but shall not find them — those who war against you shall be as nothing. The total defeat of opposition to YHWH's servant anticipates the NT's confidence in Christ's ultimate triumph: 1 Corinthians 15:25 (he must reign until he has put all enemies under his feet). The enemies reduced to nothing is the eschatological horizon of the cross's victory.</p>",
"13": "<p>A shadow: <em>kî 'ănî YHWH 'Ĕlōhèkā maḥăzîq yĕmînekā hā'ōmēr lĕkā 'al-tîrā' 'ănî 'ăzartîkā</em> — for I, YHWH your God, hold your right hand; it is I who say to you, fear not, I am the one who helps you. The divine grip on the right hand — intimate, physical, sustaining — is the posture of the Father toward the Son throughout the Gospels (John 8:29: <em>he who sent me is with me; he has not left me alone</em>; Matt 3:17: <em>this is my beloved Son, with whom I am well pleased</em>). The one who holds the right hand holds the beloved servant who cannot ultimately fail.</p>",
"14": "<p>A shadow: <em>'al-tîrĕ'î tôla'at ya'ăqōb̠ mĕtê yiśrā'ēl</em> — fear not, you worm Jacob (<em>tôla'at</em>), you men of Israel. The word <em>tôla'at</em> (worm) is a profound Christological marker: Psalm 22:6, which Christ cites from the cross (<em>My God, my God, why have you forsaken me?</em> — Matt 27:46), opens: <em>I am a worm and not a man</em> (Ps 22:6, same word <em>tôla'at</em>). The one who addresses Israel as <em>worm Jacob</em> will himself be addressed as a worm in the crucifixion psalm. YHWH speaks to Israel from the position of solidarity — the coming Servant will occupy the very position of <em>worm</em> that this verse names.</p>",
"15": "<p>A shadow: I will make you a threshing sledge — new, sharp, with many teeth — you shall thresh the mountains and crush them. The transformed servant as an instrument of divine judgment on the nations is the type of Christ's people as co-regents in the eschatological reign: Revelation 2:26-27 (to the one who conquers I will give authority over the nations to rule them with a rod of iron); 1 Corinthians 6:2-3 (the saints will judge the world). The worm of v. 14 becomes the threshing instrument of v. 15 — transformation by divine action.</p>",
"16": "<p>A shadow: you shall winnow them and the wind shall carry them away — and you shall rejoice in YHWH and glory in the Holy One of Israel. The winnowing of enemies and the resulting joy anticipates the resurrection-joy of Christ's victory: John 16:22 (your sorrow will turn into joy, and no one will take your joy from you); Revelation 19:1-7 (the great hallelujah when YHWH reigns and the enemy is defeated). The Holy One of Israel in whose victory Israel rejoices is the Christ in whose resurrection victory believers rejoice.</p>",
"17": "<p>A shadow: the poor and needy seek water and there is none — their tongue is parched with thirst. YHWH will answer them; the God of Israel will not forsake them. Christ as the answer to the deepest thirst: John 4:13-14 (whoever drinks of the water I give will never be thirsty again); John 7:37-38 (if anyone thirsts, let him come to me and drink). The poor and needy who seek water in the wilderness are the type of all who seek the living water that only Christ provides.</p>",
"18": "<p>A shadow: YHWH opens rivers on the bare heights and springs in the middle of the valleys; the wilderness becomes a pool, the dry land springs of water. The transformation of desert into water-abundance is the image of spiritual renewal through the Spirit: John 7:38-39 (rivers of living water flowing from the believer, which he said about the Spirit); Revelation 22:1-2 (the river of the water of life flowing from the throne of God and of the Lamb). Christ opens rivers in the spiritual wilderness that Isaiah 41:18 describes literally.</p>",
"19": "<p>A shadow: YHWH plants in the wilderness cedar, acacia, myrtle, olive, cypress, plane, and pine — seven trees of life transforming the desert. The number seven and the variety of life-giving trees anticipates the tree of life of Revelation 22:2 (yielding twelve kinds of fruit every month, and leaves for healing). The desert transformed into garden is the new-creation trajectory of Christ's work: 2 Corinthians 5:17 (if anyone is in Christ, new creation!). The barren wilderness becomes a garden, reversal of the Eden-to-desert trajectory of sin.</p>",
"20": "<p>A revelation of God: <em>lĕma'an yir'û wĕyēdĕ'û wĕyāśîmû wĕyaśkîlû yaḥdāw kî yad-YHWH 'āśĕtāh zō't</em> — so that all may see and know, consider and understand together, that the hand of YHWH has done this. The purpose of the transformation is knowledge of YHWH — not merely abundance, but recognition of the divine agent. John 10:38 (the works themselves testify that the Father has sent me); John 17:3 (eternal life is knowing the Father and the Son). The transformation of wilderness to garden is a sign — Christ's works are signs (John 2:11; 20:30-31) that generate the same recognition: the hand of God has done this.</p>",
"21": "<p>A revelation of God: set forth your case (<em>qirbû rîb̠ĕkem</em>), says YHWH; bring your proofs, says the King of Jacob. The divine legal challenge to idols — produce your evidence, demonstrate your power to predict — establishes YHWH as the only true witness. Christ as the fulfillment of prophecy is the supreme demonstration of divine foreknowledge: Luke 24:44 (everything written in the Law, the Prophets, and the Psalms about me must be fulfilled); 2 Peter 1:19-21 (the prophetic word confirmed as a lamp shining in a dark place).</p>",
"22": "<p>A revelation of God: let the idols tell what is to come — declare the former things so we may consider them; or announce to us what is coming, that we may know its outcome. The test of deity is foreknowledge and fulfillment. This is the epistemological ground on which Jesus' resurrection validates his claims: Acts 17:31 (God has given assurance to all by raising him from the dead). The prophetic word fulfilled in Christ is YHWH's answer to the idol-challenge of Isaiah 41:22.</p>",
"23": "<p>A revelation of God: tell what is to come hereafter, that we may know you are gods; do either good or harm, that we may be dismayed and terrified. The standard for divine identity: predictive word and active power. The idols meet neither criterion. Christ meets both: John 13:19 (I am telling you this now before it takes place, so that when it does take place you may believe that I am he); John 11:25-26 (I am the resurrection and the life — and then he raises Lazarus). The <em>ego eimi</em> of John is Isaiah 41:4 applied to the one who does what idols cannot.</p>",
"24": "<p>A revelation of God: behold, you are nothing (<em>'ayin attem</em>), and your work is less than nothing; an abomination is he who chooses you. The absolute nothingness of idols is the NT's verdict on all false worship: 1 Corinthians 8:4 (an idol has no real existence; there is no God but one); Acts 17:29 (we ought not to think that the divine being is like gold or silver or stone). The one who is not nothing — who fills all things (Eph 4:10) — stands in absolute contrast to the idols who are less than nothing.</p>",
"25": "<p>A revelation of God: YHWH stirs up one from the north — he calls on YHWH's name; he treads on rulers as on mortar. The Cyrus prophecy continues: the one YHWH calls is the one who responds to YHWH's name and who overcomes rulers. The pattern — divine call, responsive acknowledgment, unstoppable advance — is the pattern of Christ: the Father calls, the Son responds in perfect obedience (John 17:4: <em>I glorified you on earth, having accomplished the work that you gave me to do</em>), and his name is above every name (Phil 2:9-10).</p>",
"26": "<p>A revelation of God: who declared it from the beginning, that we might know, or from former times, that we might say, <em>he is right</em>? No one declared it, no one proclaimed it, no one heard your words. The argument from fulfilled prophecy is YHWH's exclusive credential. Fulfilled prophecy in Christ is the NT's repeated defense of the gospel: Acts 2:25-31 (David foresaw the resurrection); Acts 3:18 (what God foretold by the mouth of all the prophets, he fulfilled); 1 Corinthians 15:3-4 (Christ died for our sins in accordance with the scriptures; he was raised on the third day in accordance with the scriptures).</p>",
"27": "<p>A shadow: <em>ri'šôn lĕṢiyyôn hinnēh hinnām ûlĕYĕrûšālaim mĕb̠aśśēr 'ettēn</em> — I was the first to say to Zion, <em>behold, here they are!</em> and I give to Jerusalem a herald of good news. The good news (<em>mĕb̠aśśēr</em> — one who brings good news, same root as the gospel verb in 40:9; 52:7) announced to Zion first is the pattern of Christ's proclamation: Acts 3:26 (to you first God sent his servant to bless you); Romans 1:16 (to the Jew first and also to the Greek). The herald of good news given to Jerusalem is the type of the gospel itself — the announcement that what YHWH promised has come.</p>",
"28": "<p>A revelation of God: when I look, there is no one — no counselor, no one who gives an answer when I ask. The complete silence of all human wisdom before YHWH's challenge to the idols. 1 Corinthians 1:20 (where is the one who is wise? where is the debater of this age? has not God made foolish the wisdom of the world?). Christ alone is the wisdom of God (1 Cor 1:24: Christ the power of God and the wisdom of God) — the answer to the silence of Isaiah 41:28.</p>",
"29": "<p>A revelation of God: behold, they are all a delusion (<em>'āwen</em> — vanity, emptiness); their works are nothing; their metal images are empty wind. The final verdict on idols — emptiness, wind, nothing — is the condition from which Christ delivers. Ephesians 2:12 describes the pre-gospel condition: without hope and without God in the world — the emptiness of Isaiah 41:29 lived experientially. Christ fills the emptiness (Eph 1:23: the fullness of him who fills all in all) — the anti-idol who is not wind and emptiness but the one in whom the fullness of deity dwells bodily (Col 2:9).</p>"
}
}

def main():
    existing = load_comm('mkt-christ', 'isaiah')
    merge_comm(existing, ISAIAH)
    save_comm('mkt-christ', 'isaiah', existing)
    v = sum(len(vs) for vs in ISAIAH.values())
    print(f'Isaiah 41 mkt-christ: {v} verses written.')

if __name__ == '__main__':
    main()
